mapper.update:
UPDATE cotdl.tbl_testdata
SET disposal_sche_date = STR_TO_DATE(#{disposalScheDate}, '%Y/%m/%d')
WHERE testdataid = #{testdataid}

mapper.select:
SELECT a.testdataid, a.system, concat(a.sourcedb,' [', p.env,']') as sourcedb, concat(a.targetdb,' [', d.env,']') as targetdb, a.phase, a.apply_type, a.new_orderid, COALESCE(j.jobname, a.jobid) as jobid, COALESCE(t.idname, '고객번호') AS idtype, a.custid, a.custid_new, a.cust_nm, a.ssn, a.new_jobid, a.status, /*DATE_FORMAT(a.approve_date,'%Y/%m/%d %H:%i:%s')*/j.JOBNAME AS approve_date, DATE_FORMAT(a.regdate,'%Y/%m/%d') AS regdate, DATE_FORMAT(a.upddate,'%Y/%m/%d') AS upddate, a.reguserid, a.upduserid , b.requesterid AS reguserid, b.requestername AS upduserid , a.disposal_status, DATE_FORMAT(a.disposal_sche_date,'%Y/%m/%d') as disposal_sche_date, DATE_FORMAT(a.disposal_exec_date,'%Y/%m/%d') as disposal_exec_date FROM cotdl.tbl_testdata a INNER JOIN ( SELECT jobid, requesterid, requestername FROM cotdl.tbl_piiapprovalreq WHERE approvalid = 'TESTDATA_APPROVAL' AND reqid IN ( SELECT MAX(reqid) FROM cotdl.tbl_piiapprovalreq WHERE approvalid = 'TESTDATA_APPROVAL' GROUP BY jobid ) ) b ON a.testdataid = b.jobid
LEFT OUTER JOIN COTDL.TBL_TESTDATAIDTYPE t ON a.idtype = t.id LEFT OUTER JOIN ( SELECT jobid, jobname FROM COTDL.TBL_PIIJOB WHERE STATUS='ACTIVE' AND PHASE='CHECKIN' GROUP BY jobid, jobname ) j ON a.jobid = j.jobid LEFT OUTER JOIN COTDL.TBL_PIIDATABASE p ON p.db = a.sourcedb LEFT OUTER JOIN COTDL.TBL_PIIDATABASE d ON d.db = a.targetdb
order by a.testdataid desc limit #{offset}, #{amount}
